'use strict';

function renderTable(rows, options) {
  // Calculate column widths
  const columnWidths = rows[0].map((_, colIndex) => {
    return Math.max(...rows.map(row => row[colIndex].length));
  });

  // Determine alignment for each column (default to 'left')
  const align = options?.align || columnWidths.map(() => 'left');

  // Format each row
  let lines = rows.map(row => {
    const cells = row.map((cell, colIndex) => {
      const width = columnWidths[colIndex];
      if (align[colIndex] === 'right') {
        return cell.padStart(width);
      } else {
        return cell.padEnd(width);
      }
    });
    return cells.join(' ').trimEnd();
  });

  // Add header separator if requested
  if (options?.header) {
    const separatorLine = '-'.repeat(lines[0].length);
    lines.splice(1, 0, separatorLine);
  }

  return lines.join('\n');
}

function renderTableLegacy(rows) {
  return renderTable(rows);
}

module.exports = { renderTable, renderTableLegacy };
